const AWS = require('aws-sdk');
const dynamo = new AWS.DynamoDB.DocumentClient();

exports.handler = async (event) => {
  const orders = event.Records;

  try {
    await Promise.all(orders.map(async (order) => {
      const { body } = order;
      const { paymentMethod, paymentToken, total } = JSON.parse(body);
      let paid = false;

      if (paymentMethod === 'paypal') {
        // Call PayPal API to process payment
        const paypalResponse = await fetch('https://api.paypal.com/v1/payments/payment', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ payment_method: paymentMethod, payment_token: paymentToken }),
        });
        paid = true;
      } else if (paymentMethod === 'stripe') {
        // Call Stripe API to process payment
        const stripeResponse = await fetch('https://api.stripe.com/v1/charges', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ amount: total, currency: 'USD', source: paymentToken }),
        });
        paid = true;
      }

      if (paid) {
        try {
          const orderData = {
            orderId: order.messageId,
            status: 'PAID',
            timestamp: new Date(),
          };

          await dynamo.update({
            TableName: 'ordersTable',
            Key: { id: order.messageId },
            UpdateExpression: 'set #status = :s, #timestamp = :t',
            ExpressionAttributeNames: {
              '#status': 'status',
              '#timestamp': 'timestamp'
            },
            ExpressionAttributeValues: {
              ':s': 'PAID',
              ':t': new Date(),
            }
          }).promise();

        } catch (err) {
          console.error(`Error updating DynamoDB record for order ${order.messageId}:`, err);
        }
      }
    }));
  } catch (err) {
    console.error('Error processing orders:', err);
  }

  return { statusCode: 200 };
};